// Dart programlama dili
void main() {
  // Değişkenler
  String isim = 'Flutter';
  int yil = 2018;
  double versiyon = 3.0;
  bool aktif = true;

  print('$isim $yil\'de çıktı');
  print('Versiyon: $versiyon');

  // List
  List<String> platformlar = [
    'Android', 'iOS', 'Web', 'Windows'
  ];

  for (String platform in platformlar) {
    print('  ✓ $platform');
  }

  // Null safety
  String? nullable = null;
  print(nullable ?? 'Değer yok');  // null ise alternatif
}

import 'package:flutter/material.dart';

void main() {
  runApp(const MyApp());
}

// Stateless Widget - değişmez
class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Demo',
      debugShowCheckedModeBanner: false,
      theme: ThemeData(
        colorScheme: ColorScheme.fromSeed(
          seedColor: Colors.blue,
        ),
      ),
      home: const AnaSayfa(),
    );
  }
}

// Stateful Widget - değişir
class AnaSayfa extends StatefulWidget {
  const AnaSayfa({super.key});

  @override
  State<AnaSayfa> createState() => _AnaSayfaState();
}

class _AnaSayfaState extends State<AnaSayfa> {
  int _sayac = 0;

  void _artir() {
    setState(() {  // UI'ı yenile
      _sayac++;
    });
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Widget Demo'),
        backgroundColor: Colors.blue,
        foregroundColor: Colors.white,
      ),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            const Text(
              'Butona kaç kez bastın:',
              style: TextStyle(fontSize: 18),
            ),
            Text(
              '$_sayac',
              style: const TextStyle(
                fontSize: 64,
                fontWeight: FontWeight.bold,
                color: Colors.blue,
              ),
            ),
          ],
        ),
      ),
      floatingActionButton: FloatingActionButton(
        onPressed: _artir,
        child: const Icon(Icons.add),
      ),
    );
  }
}

import 'package:flutter/material.dart';

void main() => runApp(const MaterialApp(
  home: LayoutDemo(),
));

class LayoutDemo extends StatelessWidget {
  const LayoutDemo({super.key});

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Layout Demo')),
      body: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            // Row - yatay dizilim
            const Text('Row örneği:',
              style: TextStyle(fontWeight: FontWeight.bold)),
            Row(
              mainAxisAlignment: MainAxisAlignment.spaceEvenly,
              children: [
                _RenkliKutu(Colors.red, 'Kırmızı'),
                _RenkliKutu(Colors.green, 'Yeşil'),
                _RenkliKutu(Colors.blue, 'Mavi'),
              ],
            ),
            const SizedBox(height: 20),

            // Expanded - esnek genişlik
            const Text('Expanded örneği:',
              style: TextStyle(fontWeight: FontWeight.bold)),
            Row(
              children: [
                Expanded(
                  flex: 2,
                  child: Container(
                    height: 50,
                    color: Colors.orange,
                    child: const Center(child: Text('2 birim')),
                  ),
                ),
                Expanded(
                  flex: 1,
                  child: Container(
                    height: 50,
                    color: Colors.purple,
                    child: const Center(
                      child: Text('1 birim',
                        style: TextStyle(color: Colors.white)),
                    ),
                  ),
                ),
              ],
            ),
            const SizedBox(height: 20),

            // Stack - üst üste
            const Text('Stack örneği:',
              style: TextStyle(fontWeight: FontWeight.bold)),
            SizedBox(
              height: 100,
              child: Stack(
                children: [
                  Container(
                    width: double.infinity,
                    color: Colors.blue[100],
                    child: const Center(child: Text('Arka Plan')),
                  ),
                  Positioned(
                    top: 10, right: 10,
                    child: Container(
                      padding: const EdgeInsets.all(6),
                      color: Colors.red,
                      child: const Text('Rozet',
                        style: TextStyle(color: Colors.white)),
                    ),
                  ),
                ],
              ),
            ),
          ],
        ),
      ),
    );
  }
}

class _RenkliKutu extends StatelessWidget {
  final Color renk;
  final String metin;
  const _RenkliKutu(this.renk, this.metin);

  @override
  Widget build(BuildContext context) {
    return Container(
      width: 80, height: 80,
      color: renk,
      child: Center(
        child: Text(metin,
          style: const TextStyle(color: Colors.white)),
      ),
    );
  }
}

import 'package:flutter/material.dart';

void main() => runApp(const MaterialApp(
  debugShowCheckedModeBanner: false,
  home: AnaSayfa(),
));

class AnaSayfa extends StatelessWidget {
  const AnaSayfa({super.key});

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Ana Sayfa'),
        backgroundColor: Colors.blue,
        foregroundColor: Colors.white,
      ),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            ElevatedButton(
              onPressed: () {
                // Yeni sayfaya git
                Navigator.of(context).push(
                  MaterialPageRoute(
                    builder: (context) => const DetaySayfa(
                      baslik: 'Flutter Dersleri',
                      icerik: 'Bu sayfada detaylı bilgi var.',
                    ),
                  ),
                );
              },
              child: const Text('Detay Sayfasına Git'),
            ),
            const SizedBox(height: 16),
            ElevatedButton(
              style: ElevatedButton.styleFrom(
                backgroundColor: Colors.green,
              ),
              onPressed: () async {
                // Veri ile git ve veri döndür
                final sonuc = await Navigator.of(context).push<String>(
                  MaterialPageRoute(
                    builder: (context) => const VeriDondurSayfa(),
                  ),
                );
                // ignore: use_build_context_synchronously
                ScaffoldMessenger.of(context).showSnackBar(
                  SnackBar(content: Text(sonuc ?? 'İptal edildi')),
                );
              },
              child: const Text('Veri Al'),
            ),
          ],
        ),
      ),
    );
  }
}

class DetaySayfa extends StatelessWidget {
  final String baslik;
  final String icerik;

  const DetaySayfa({
    super.key,
    required this.baslik,
    required this.icerik,
  });

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(baslik),
        // Otomatik geri butonu eklenir
      ),
      body: Padding(
        padding: const EdgeInsets.all(24),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text(baslik,
              style: const TextStyle(
                fontSize: 28, fontWeight: FontWeight.bold)),
            const SizedBox(height: 16),
            Text(icerik, style: const TextStyle(fontSize: 16)),
            const SizedBox(height: 32),
            ElevatedButton(
              onPressed: () => Navigator.of(context).pop(),
              child: const Text('Geri Dön'),
            ),
          ],
        ),
      ),
    );
  }
}

class VeriDondurSayfa extends StatelessWidget {
  const VeriDondurSayfa({super.key});

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Seçim Yap')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            ElevatedButton(
              onPressed: () => Navigator.pop(context, 'Elma seçildi!'),
              child: const Text('🍎 Elma'),
            ),
            ElevatedButton(
              onPressed: () => Navigator.pop(context, 'Armut seçildi!'),
              child: const Text('🍐 Armut'),
            ),
          ],
        ),
      ),
    );
  }
}

lessons.detail:
Navigator metodları:

• Navigator.push(context, route) → Sayfayı stack'e ekle
• Navigator.pop(context) → Geri dön, son sayfayı kaldır
• Navigator.pushReplacement(context, route) → Mevcut sayfayı değiştir
• Navigator.pushAndRemoveUntil() → Belirli sayfaya kadar temizle

Veri gönderme:
Navigator.push(
  context,
  MaterialPageRoute(
    builder: (_) => DetaySayfa(id: 5, baslik: 'Başlık'),
  ),
);

Veri alma (await ile):
final sonuc = await Navigator.push<String>(...);
// Kullanıcı geri dönünce sonuc dolu gelir

Named Routes (büyük projeler için):
MaterialApp(
  routes: {
    '/': (ctx) => AnaSayfa(),
    '/detay': (ctx) => DetaySayfa(),
  },
);
Navigator.pushNamed(context, '/detay');

PageRoute alternatifleri:
• MaterialPageRoute → Android/iOS varsayılan animasyon
• CupertinoPageRoute → iOS animasyonu (Android'de de)
• PageRouteBuilder → Özel animasyon

Scaffold.of(context) vs Navigator.of(context):
Her ikisi de context'ten yükseltilir. BuildContext doğru widget'ın altında olmalı.

