// pubspec.yaml'a ekle:
// provider: ^6.0.0

import 'package:flutter/material.dart';
import 'package:provider/provider.dart';

// 1. State sınıfı
class SayacModel extends ChangeNotifier {
  int _sayac = 0;

  int get sayac => _sayac;

  void artir() {
    _sayac++;
    notifyListeners(); // Dinleyicileri bildir
  }

  void azalt() {
    if (_sayac > 0) {
      _sayac--;
      notifyListeners();
    }
  }

  void sifirla() {
    _sayac = 0;
    notifyListeners();
  }
}

void main() {
  runApp(
    // 2. Provider ile sar
    ChangeNotifierProvider(
      create: (_) => SayacModel(),
      child: const MaterialApp(
        debugShowCheckedModeBanner: false,
        home: SayacSayfasi(),
      ),
    ),
  );
}

class SayacSayfasi extends StatelessWidget {
  const SayacSayfasi({super.key});

  @override
  Widget build(BuildContext context) {
    // 3. State'i oku
    final model = Provider.of<SayacModel>(context);

    return Scaffold(
      appBar: AppBar(
        title: const Text('Provider Demo'),
        actions: [
          IconButton(
            icon: const Icon(Icons.refresh),
            onPressed: model.sifirla,
          ),
        ],
      ),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Text(
              '${model.sayac}',
              style: const TextStyle(
                fontSize: 80,
                fontWeight: FontWeight.bold,
              ),
            ),
            const SizedBox(height: 32),
            Row(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                FloatingActionButton(
                  heroTag: 'azalt',
                  onPressed: model.azalt,
                  child: const Icon(Icons.remove),
                ),
                const SizedBox(width: 24),
                FloatingActionButton(
                  heroTag: 'artir',
                  onPressed: model.artir,
                  child: const Icon(Icons.add),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }
}
